import java.util.Scanner;

public class SecureBufferOverflow {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Implementing proper length validation to prevent buffer overflow
        if (name.length() > 100) {
            System.out.println("Input is too long. Please enter a shorter name.");
            return;
        }

        String greeting = "Hello, " + name + "! Welcome to our system.";

        System.out.println(greeting);
    }
}

### Explanation:
취약유형: Buffer Overflow
